mapper.select:
select m6.sys_id, m6.third_party_name, m6.success, m6.failed, ( case when m5.task_count is null then 0 else m5.task_count end ) task_count from ( select m1.sysid sys_id, m1.thirdpartyname third_party_name, sum ( case success when 1 then 1 else 0 end ) success, sum ( case success when 0 then 1 else 0 end ) failed from vzdataquality.dbo.thridparty m1 left join vzdataquality.dbo.tb_collectiontimingdata m2 on m1.sysid = m2.company_id left join vzdataquality.dbo.tb_collectionlog as m3 on m2.id = m3.task_id
m1.ThirdPartyName like CONCAT('%',#{map.name},'%')
and m3.begin_time >= #{map.beginTime}
and m3.begin_time <= #{map.endTime}
and m2.type=#{map.type}
group by m1.sysid, m1.thirdpartyname ) as m6 left join ( select count (id) task_count, company_id from vzdataquality.dbo.tb_collectiontimingdata
and type=#{map.type}
group by company_id ) m5 on m5.company_id = m6.sys_id

select m3.*,m4.work_untis_code,m4.work_untis_name,m5.NAME tran_name from ( select m1.id, count(m2.task_id) count, sum(case m2.success when 1 then 1 else 0 end) success, sum(case m2.success when 0 then 1 else 0 end) failed from VzDataQuality.dbo.tb_collectiontimingdata m1 left join VzDataQuality.dbo.tb_collectionlog m2 on m1.id=m2.task_id
m1.company_id like CONCAT('%',#{map.company_id},'%')
and m2.begin_time >= #{map.beginTime}
and m2.begin_time <= #{map.endTime}
and m1.type=#{map.type}
group by m1.id) m3 left join VzDataQuality.dbo.tb_collectiontimingdata m4 on m3.id=m4.id left join VzDataQuality.dbo.r_transformation m5 on m4.tran_id=m5.ID_TRANSFORMATION
